export const routes = [
  {
    path: 'checkout',
    loadChildren: () => loadRemoteModule('checkout', './Routes'),
  },
];

export default [
  { path: '', loadComponent: () => import('./checkout.page') },
  { path: 'success', loadComponent: () => import('./success.page') },
];

export const shared = {
  '@angular/core': { singleton: true, strictVersion: true },
  '@angular/router': { singleton: true, strictVersion: true },
};
